// Normaliza o feedback: aceita arrays ou strings separadas por vírgula/;/linha.
const b = $input.first().json || {};
const body = b.body || b;
const linha = String(body.linha || '').trim();
if (!linha) throw new Error('linha do catálogo é obrigatória.');
const edital_id = String(body.edital_id || '').trim();
const acao = String(body.acao || '').trim();

const splitTerms = (v) => Array.isArray(v) ? v : String(v || '').split(/[,;\n]/);
const clean = (s) => String(s || '').trim();
const uniq = (arr) => {
  const seen = new Set(); const out = [];
  for (const x of arr) { const k = x.toLowerCase(); if (!seen.has(k)) { seen.add(k); out.push(x); } }
  return out;
};

const boas  = uniq(splitTerms(body.palavras_boas).map(clean).filter(x => x.length >= 2)).slice(0, 20);
const ruins = uniq(splitTerms(body.palavras_ruins).map(clean).filter(x => x.length >= 2)).slice(0, 20);
let regra = clean(body.regra);
if (regra.length > 280) regra = regra.slice(0, 280);

// Lista única de textos p/ embeddar, com mapa de volta.
const inputs = [];
const map = { boas: [], ruins: [], regra: -1 };
boas.forEach(t => { map.boas.push(inputs.length); inputs.push(t); });
ruins.forEach(t => { map.ruins.push(inputs.length); inputs.push(t); });
if (regra.length >= 4) { map.regra = inputs.length; inputs.push(regra); }

return [{ json: { linha, edital_id, acao, boas, ruins, regra, inputs, map, tem: inputs.length > 0 } }];

// Casa os embeddings de volta aos candidatos. Se faltar embedding
// (falha do nó), degrada para dedup EXATA apenas (sem o campo embedding).
const meta = $('Normalizar Feedback').first().json;
const resp = $input.first().json || {};
const embs = Array.isArray(resp.data) ? resp.data.map(d => d && d.embedding) : [];
const hasEmb = embs.length === meta.inputs.length && embs.every(e => Array.isArray(e) && e.length > 0);
const getEmb = (i) => (hasEmb && i >= 0) ? embs[i] : null;

const boas = meta.boas.map((t, k) => { const e = getEmb(meta.map.boas[k]); return e ? { termo: t, embedding: e } : { termo: t }; });
const ruins = meta.ruins.map((t, k) => { const e = getEmb(meta.map.ruins[k]); return e ? { termo: t, embedding: e } : { termo: t }; });
let regra = null;
if (meta.map.regra >= 0) { const e = getEmb(meta.map.regra); regra = e ? { texto: meta.regra, embedding: e } : { texto: meta.regra }; }

const payload = {
  linha: meta.linha,
  origem_edital_id: meta.edital_id || null,
  origem_acao: meta.acao || null,
  limiar_termo: 0.90,
  limiar_regra: 0.86,
  boas, ruins, regra
};
const b64 = Buffer.from(JSON.stringify(payload), 'utf8').toString('base64');
return [{ json: { b64, edital_id: meta.edital_id, dedup_semantica: hasEmb } }];
